--
-- Table structure for table `student_promotion_logs`
--

DROP TABLE IF EXISTS `student_promotion_logs`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `student_promotion_logs` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `source_academic_year_id` bigint(20) unsigned NOT NULL,
  `target_academic_year_id` bigint(20) unsigned NOT NULL,
  `promoted_count` int(11) NOT NULL DEFAULT 0,
  `total_count` int(11) NOT NULL DEFAULT 0,
  `errors_count` int(11) NOT NULL DEFAULT 0,
  `performed_by` bigint(20) unsigned NOT NULL,
  `performed_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  `additional_data` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`additional_data`)),
  `notes` text DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `student_promotion_logs_target_academic_year_id_foreign` (`target_academic_year_id`),
  KEY `promotion_years_idx` (`source_academic_year_id`,`target_academic_year_id`),
  KEY `student_promotion_logs_performed_by_index` (`performed_by`),
  KEY `student_promotion_logs_performed_at_index` (`performed_at`),
  CONSTRAINT `student_promotion_logs_performed_by_foreign` FOREIGN KEY (`performed_by`) REFERENCES `users` (`id`) ON DELETE CASCADE,
  CONSTRAINT `student_promotion_logs_source_academic_year_id_foreign` FOREIGN KEY (`source_academic_year_id`) REFERENCES `academic_years` (`id`) ON DELETE CASCADE,
  CONSTRAINT `student_promotion_logs_target_academic_year_id_foreign` FOREIGN KEY (`target_academic_year_id`) REFERENCES `academic_years` (`id`) ON DELETE CASCADE
